class Stack:
    def __init__(self, max_size=10):
        self._stack = []
        self._max_size = max_size

    def push(self, value):
        if len(self._stack) >= self._max_size:
            return False
        self._stack.append(value)
        return True

    def pop(self):
        if not self._stack:
            return None
        return self._stack.pop()

    def peek(self):
        if not self._stack:
            return None
        return self._stack[-1]

    def is_empty(self):
        return not self._stack

    def get_size(self):
        return len(self._stack)
